<script setup>import { onMounted, ref } from 'vue'; import { api } from '../api'; const items=ref([]); onMounted(async()=>{items.value=(await api('/notifications')).data;});</script><template><main class="center"><section class="card"><h1>Notifications</h1><article v-for="item in items" :key="item.id"><strong>{{ item.title }}</strong><p>{{ item.body }}</p></article><RouterLink to="/">Back</RouterLink></section></main></template>
